export default "<!DOCTYPE html><script type=\"application/json\" id=\"cowork-artifact-meta\">\n{\n  \"name\": \"Contentious Health Longevity News\",\n  \"schemaVersion\": 1,\n  \"description\": \"Daily briefing of the most contentious/debated stories in health and longevity. Rebuilt each morning at 8:00 AM by a scheduled task (web search). Includes a \\\"Refresh now\\\" button that triggers the task on demand.\"\n}\n</script>\n<html lang=\"en\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n<title>Contentious Health &amp; Longevity News</title>\n<style>\n  :root { color-scheme: light; }\n  * { box-sizing: border-box; }\n  body {\n    margin: 0;\n    font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, Helvetica, Arial, sans-serif;\n    color: #1c1917;\n    background: #faf8f5;\n    line-height: 1.5;\n  }\n  .wrap { max-width: 760px; margin: 0 auto; padding: 24px 20px 56px; }\n  header { border-bottom: 2px solid #e7e1d8; padding-bottom: 16px; margin-bottom: 8px; }\n  .kicker { font-size: 12px; font-weight: 700; letter-spacing: .08em; text-transform: uppercase; color: #b45309; }\n  h1 { font-size: 26px; margin: 6px 0 4px; line-height: 1.2; }\n  .meta { font-size: 13px; color: #78716c; }\n  .controls { display: flex; align-items: center; gap: 12px; flex-wrap: wrap; margin: 16px 0 20px; }\n  button.refresh {\n    appearance: none; border: 1px solid #d6cfc4; background: #fff; color: #1c1917;\n    font-size: 13px; font-weight: 600; padding: 8px 14px; border-radius: 8px; cursor: pointer;\n  }\n  button.refresh:hover { background: #f5f1ea; }\n  button.refresh:disabled { opacity: .55; cursor: default; }\n  .status { font-size: 12.5px; color: #78716c; }\n  .item {\n    background: #fff; border: 1px solid #ece6dd; border-left: 4px solid #d97706;\n    border-radius: 10px; padding: 16px 18px; margin: 14px 0;\n  }\n  .item h2 { font-size: 17px; margin: 0 0 6px; line-height: 1.3; }\n  .tag {\n    display: inline-block; font-size: 11px; font-weight: 700; text-transform: uppercase;\n    letter-spacing: .04em; color: #92400e; background: #fef3c7; border-radius: 999px;\n    padding: 2px 9px; margin-bottom: 8px;\n  }\n  .item p { margin: 8px 0; font-size: 14.5px; }\n  .sides { font-size: 13.5px; margin-top: 8px; }\n  .sides b { color: #44403c; }\n  .src { margin-top: 10px; font-size: 12.5px; }\n  .src a { color: #b45309; text-decoration: none; }\n  .src a:hover { text-decoration: underline; }\n  .src a + a::before { content: \" · \"; color: #a8a29e; }\n\n  .tweet { margin-top: 13px; background: #fbfaf8; border: 1px solid #ece6dd; border-radius: 8px; padding: 10px 12px; }\n  .tweet-head { display: flex; align-items: center; justify-content: space-between; gap: 8px;\n    font-size: 11px; font-weight: 700; text-transform: uppercase; letter-spacing: .05em; color: #92400e; margin-bottom: 7px; }\n  .tweet-body { white-space: pre-line; font-size: 13.5px; color: #1c1917; line-height: 1.5; }\n  button.copy { appearance: none; border: 1px solid #d6cfc4; background: #fff; color: #1c1917;\n    font-size: 11px; font-weight: 600; padding: 3px 10px; border-radius: 6px; cursor: pointer; white-space: nowrap; }\n  button.copy:hover { background: #f5f1ea; }\n  footer { margin-top: 28px; font-size: 12px; color: #a8a29e; border-top: 1px solid #e7e1d8; padding-top: 14px; }\n</style>\n</head>\n<body>\n<div class=\"wrap\">\n  <header>\n    <div class=\"kicker\">Daily Briefing · Auto-updates 8:00 AM</div>\n    <h1>Contentious Health &amp; Longevity News</h1>\n    <div class=\"meta\" id=\"asof\">As of Saturday, June 27, 2026</div>\n  </header>\n\n  \n\n  <div class=\"item\">\n    <span class=\"tag\">Most contentious</span>\n    <h2>Are the world&rsquo;s &ldquo;Blue Zones&rdquo; real &mdash; or built on broken records?</h2>\n    <p>A renewed clash (STAT, May 2026) pits Ig Nobel&ndash;winning demographer Saul Newman against the Blue Zones brand. His analysis argues the centenarian hotspots track missing birth records, clerical errors and pension fraud &mdash; e.g. after Costa Rica corrected ages, the Nicoya zone shrank roughly 90%.</p>\n    <div class=\"sides\"><b>The fight:</b> Newman says the longevity is a statistical mirage from bad data; Dan Buettner and Blue Zones researchers say validated registries and the diet-and-community findings still hold.</div>\n    <div class=\"src\"><a href=\"https://www.statnews.com/2026/05/04/are-blue-zones-real-new-scrutiny-longevity-hot-spots/\" target=\"_blank\" rel=\"noopener\">STAT</a><a href=\"https://www.science.org/content/article/do-blue-zones-supposed-havens-longevity-rest-shaky-science\" target=\"_blank\" rel=\"noopener\">Science</a></div>\n    <div class=\"tweet\">\n      <div class=\"tweet-head\"><span>✎ Suggested tweet</span><button class=\"copy\" onclick=\"copyTweet(this)\">Copy</button></div>\n      <div class=\"tweet-body\">The world&rsquo;s most famous longevity hotspots may be a data error.\nFix Costa Rica&rsquo;s age records and its &ldquo;Blue Zone&rdquo; shrinks ~90%.\nOne Ig Nobel demographer says it&rsquo;s pension fraud, not diet.\nSo what exactly are we all copying?</div>\n    </div>\n  </div>\n\n  <div class=\"item\">\n    <span class=\"tag\">Drug debate</span>\n    <h2>A transplant drug matches starvation diets for lifespan &mdash; in animals</h2>\n    <p>A 2025 Aging Cell meta-analysis (911 effect sizes, 167 papers, 8 vertebrate species) found rapamycin extends life about as well as calorie restriction &mdash; while metformin showed no significant lifespan effect. No human trial has yet shown rapamycin extends lifespan, and it suppresses the immune system.</p>\n    <div class=\"sides\"><b>The fight:</b> Enthusiasts say the animal evidence rivals eating less and justifies cautious off-label use; skeptics say zero human lifespan data plus immune risks make that reckless.</div>\n    <div class=\"src\"><a href=\"https://medicalxpress.com/news/2025-06-rapamycin-lifespan-effectively.html\" target=\"_blank\" rel=\"noopener\">Medical Xpress</a><a href=\"https://onlinelibrary.wiley.com/doi/10.1111/acel.70131\" target=\"_blank\" rel=\"noopener\">Aging Cell</a></div>\n    <div class=\"tweet\">\n      <div class=\"tweet-head\"><span>✎ Suggested tweet</span><button class=\"copy\" onclick=\"copyTweet(this)\">Copy</button></div>\n      <div class=\"tweet-body\">A transplant drug just matched a starvation diet for extending life.\n167 studies, 8 species: rapamycin rivaled eating less &mdash; metformin didn&rsquo;t.\nThe catch: zero proof it extends human life, and it dials down immunity.\nAnimal data isn&rsquo;t a prescription.</div>\n    </div>\n  </div>\n\n  <div class=\"item\">\n    <span class=\"tag\">Side-effect fight</span>\n    <h2>GLP-1s: longevity drug, or a shortcut to frailty?</h2>\n    <p>The same drugs hailed as anti-aging (a 2026 trial reported semaglutide slowed an epigenetic &ldquo;pace of aging&rdquo; clock ~9%) also strip lean mass: editorials peg 15&ndash;40% of weight lost on GLP-1s as muscle, raising frailty fears in older adults.</p>\n    <div class=\"sides\"><b>The fight:</b> Aging-medicine voices warn rapid muscle and bone loss mimics accelerated aging in seniors; other clinicians (Medscape) call the muscle-loss alarm overblown and largely expected with any weight loss.</div>\n    <div class=\"src\"><a href=\"https://harvardsciencereview.org/2026/02/23/the-glp-1-aftermath-what-the-science-says-about-muscle-loss-and-cellular-aging/\" target=\"_blank\" rel=\"noopener\">Harvard Science Review</a><a href=\"https://www.medscape.com/viewarticle/no-need-worry-about-glp-1-induced-muscle-loss-2026a1000dr2\" target=\"_blank\" rel=\"noopener\">Medscape</a></div>\n    <div class=\"tweet\">\n      <div class=\"tweet-head\"><span>✎ Suggested tweet</span><button class=\"copy\" onclick=\"copyTweet(this)\">Copy</button></div>\n      <div class=\"tweet-body\">Up to 40% of the weight lost on GLP-1s is muscle, not fat.\nIn older adults that can speed frailty &mdash; the opposite of longevity.\nYet a 2026 trial says these same drugs slow aging ~9%.\nAnti-aging or accelerated aging? Both camps have data.</div>\n    </div>\n  </div>\n\n  <div class=\"item\">\n    <span class=\"tag\">Data dispute</span>\n    <h2>The &ldquo;anti-aging molecule&rdquo; taurine just got contradicted</h2>\n    <p>A 2023 Columbia study found taurine falls with age and extended lifespan in mice, fueling a supplement boom. In 2025 an NIH-led Science paper and an Aging Cell study (137 men, ages 20&ndash;93) found taurine generally holds steady or rises with age &mdash; concluding it&rsquo;s not a reliable aging biomarker.</p>\n    <div class=\"sides\"><b>The fight:</b> The original authors say taurine biology still warrants human trials; the new teams say the core premise &mdash; an age-driven decline to &ldquo;top up&rdquo; &mdash; doesn&rsquo;t hold in humans.</div>\n    <div class=\"src\"><a href=\"https://www.nih.gov/news-events/news-releases/nih-researchers-conclude-taurine-unlikely-be-good-aging-biomarker\" target=\"_blank\" rel=\"noopener\">NIH</a><a href=\"https://www.livescience.com/health/ageing/taurine-is-not-a-reliable-biomarker-of-anything-yet-study-challenges-hype-over-anti-aging-supplement\" target=\"_blank\" rel=\"noopener\">Live Science</a></div>\n    <div class=\"tweet\">\n      <div class=\"tweet-head\"><span>✎ Suggested tweet</span><button class=\"copy\" onclick=\"copyTweet(this)\">Copy</button></div>\n      <div class=\"tweet-body\">Remember taurine, the &ldquo;anti-aging molecule&rdquo;? The data just flipped.\n2023: it drops with age and extends mouse lifespan.\n2025: two studies say it doesn&rsquo;t drop &mdash; sometimes it climbs.\nA hot supplement built on a biomarker that may not exist.</div>\n    </div>\n  </div>\n\n  <div class=\"item\">\n    <span class=\"tag\">Biohacker</span>\n    <h2>Tech&rsquo;s longevity bros: pioneers, or expensive performance art?</h2>\n    <p>A June 2026 Nature feature asks whether there&rsquo;s real science behind millionaire self-experimenters like Bryan Johnson, who track aging obsessively and have tried extremes (Johnson once took plasma from his teenage son before abandoning it as inconclusive).</p>\n    <div class=\"sides\"><b>The fight:</b> Fans call them transparent, in-public self-experimenters pushing the field forward; experts say most of it is unproven, expensive theater with no control group to separate the pills from sleep, diet and exercise.</div>\n    <div class=\"src\"><a href=\"https://www.nature.com/articles/d41586-026-01884-z\" target=\"_blank\" rel=\"noopener\">Nature</a><a href=\"https://www.inc.com/chase-feiger/the-doctor-who-helped-build-bryan-johnsons-blueprint-has-a-list-of-dos-and-donts-for-longevity-hackers/91335505\" target=\"_blank\" rel=\"noopener\">Inc.</a></div>\n    <div class=\"tweet\">\n      <div class=\"tweet-head\"><span>✎ Suggested tweet</span><button class=\"copy\" onclick=\"copyTweet(this)\">Copy</button></div>\n      <div class=\"tweet-body\">He tracks his aging organ by organ &mdash; and still can&rsquo;t prove it works.\nTech&rsquo;s longevity bros run $1M+ self-experiments on themselves.\nNo control group to separate the pills from sleep and exercise.\nPioneers &mdash; or expensive theater?</div>\n    </div>\n  </div>\n\n  <footer>\n    Updated Saturday, June 27, 2026 via web search. Each morning at 8:00 AM this page is rebuilt with the day&rsquo;s most-debated health &amp; longevity stories, each with a suggested tweet. Drafts only &mdash; nothing is posted.</footer>\n</div>\n\n<script>\n  function setStatus(){}\n  function refresh(){}\n  \n  function copyTweet(btn){\n    var box = btn.closest('.tweet').querySelector('.tweet-body');\n    if(!box) return;\n    var text = box.textContent.split('\\n').map(function(s){ return s.trim(); }).join('\\n').replace(/\\n{3,}/g, '\\n\\n').trim();\n    var label = btn.getAttribute('data-label') || btn.textContent;\n    btn.setAttribute('data-label', label);\n    function ok(){ btn.textContent = 'Copied!'; setTimeout(function(){ btn.textContent = label; }, 1500); }\n    function fail(){ btn.textContent = 'Select & copy'; setTimeout(function(){ btn.textContent = label; }, 2000); }\n    if(navigator.clipboard && navigator.clipboard.writeText){\n      navigator.clipboard.writeText(text).then(ok).catch(function(){ tryExec(text) ? ok() : fail(); });\n    } else { tryExec(text) ? ok() : fail(); }\n  }\n  function tryExec(text){\n    try {\n      var ta = document.createElement('textarea'); ta.value = text;\n      ta.style.position = 'fixed'; ta.style.top = '-1000px';\n      document.body.appendChild(ta); ta.focus(); ta.select();\n      var r = document.execCommand('copy'); document.body.removeChild(ta); return r;\n    } catch(e){ return false; }\n  }\n</script>\n</body>\n</html>";
